insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('economics:1-1-main-economic-groups-and-factors-of-production:exam:be3a8589', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q1", "question": "Which one of the following is not a factor of production?", "options": ["Capital", "Labour", "Land", "Money"], "hint": "Three of these are the four factors of production you''ve just learned. Money on its own isn''t one of them — it''s used to buy capital, but it isn''t capital itself.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — Money</strong></p>\n<ul>\n<li>Money is not itself a factor of production.</li>\n<li>It can be used to buy capital (machinery, tools, buildings), but capital and money are not the same thing.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:5ba5ed4a', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q3", "question": "The quantity of labour in an economy depends on the...", "options": ["Ability of entrepreneurs to organise it", "Amount of land able to support people", "Availability of human resources", "Provision of education"], "caseStudy": "One factor of production is labour.", "hint": "''Quantity'' means how much labour there IS — not how skilled it is (that''s quality, linked to education). Which option is about the number of people available to work?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — Availability of human resources</strong></p>\n<ul>\n<li>The quantity of labour depends on how many people are available and willing to work.</li>\n<li>Provision of education affects the <em>quality</em> of labour, not the quantity.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>While most candidates correctly gave C as the answer, there was a lot of support for A and D, showing misconceptions about the quantity of labour.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:829c24ac', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q4", "question": "As a producer, what is Kai not responsible for?", "options": ["Adding efficiency to the firm", "Deciding how much VAT to pay", "Making economic choices about production", "Making use of scarce resources"], "caseStudy": "Kai had an idea to set up a printing business. They rented a shop, employed staff and bought some printing equipment.", "hint": "VAT is set by the government, not by the business owner. Which option is something Kai has no control over?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Deciding how much VAT to pay</strong></p>\n<ul>\n<li>VAT rates are set by the government, not by individual producers.</li>\n<li>Kai, as a producer, IS responsible for efficiency, economic choices about production, and the use of scarce resources.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option B as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:9edfe8b1', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q5", "question": "Which group would not be classed as producers?", "options": ["Factory workers", "Self-employed individuals", "Small firms", "The government"], "hint": "Think about who actually SUPPLIES the good or service, versus who works for the business that supplies it.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — Factory workers</strong></p>\n<ul>\n<li>Factory workers are part of the labour factor of production — they are employed BY a producer, but they are not producers themselves.</li>\n<li>Self-employed individuals, small firms and the government can all supply goods and services, so they ARE producers.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>The correct response to this question was Option A.</p>\n<p>Incorrect responses frequently gave Option D or, to a lesser extent, Option B, and indicated a lack of knowledge and understanding of what constitutes a producer.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:ab446bcf', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q6", "question": "Which of these is an example of capital?", "options": ["A computer monitor", "The business owner", "The company''s shares", "The trees owned by the company"], "caseStudy": "You are the economist for a timber merchant and have been asked to advise your team leader about factors of production.", "hint": "Capital means man-made equipment used in production. Which option is a piece of equipment, not a person, a financial asset, or a natural resource?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — A computer monitor</strong></p>\n<ul>\n<li>A computer monitor is a man-made aid to production, so it counts as capital.</li>\n<li>The business owner is enterprise.</li>\n<li>The company''s shares are a financial asset — not a factor of production.</li>\n<li>The trees are land (a natural resource) — even though this is a timber merchant.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Most candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:f2660736', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Which of these is most likely to be provided by the government?", "options": ["Capital goods", "Electric cars", "Social media", "Vaccinations"], "caseStudy": "Too few resources would be allocated to certain products if left to the market.", "hint": "Think about which of these products benefits society as a whole, not just the person who buys it — the free market tends to under-supply things like this.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — Vaccinations</strong></p>\n<ul>\n<li>Vaccinations benefit the whole of society (they reduce the spread of disease), not just the person vaccinated.</li>\n<li>The free market tends to under-supply products like this, so governments often step in to provide or fund them.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Many candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:4e63b438', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q10", "question": "In a market system, decisions about what to produce are determined by the interdependence of...", "options": ["Consumers and government", "Consumers and producers", "Government and workers", "Producers and workers"], "hint": "In a market economy, which two groups interact directly through buying and selling to decide what gets made?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — Consumers and producers</strong></p>\n<ul>\n<li>In a market system, what gets produced is decided by the interaction of consumer demand and producer supply.</li>\n<li>Government and workers do not directly decide what is produced in a market system.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:3842937c', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q12", "question": "Which of the following lists contains only factors of production?", "options": ["Capital, government, money and suppliers", "Land, labour, capital and enterprise", "Land, labour, capital and money", "Machinery, buildings, output and profits"], "hint": "There''s only one option where all four items are genuine factors of production, with nothing else mixed in.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: B — Land, labour, capital and enterprise</strong></p>\n<ul>\n<li>These are the four factors of production.</li>\n<li>The other options mix in things that are NOT factors of production — government, money, suppliers, output and profits.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:d46e7ccb', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q13", "question": "Factors of production are combined to produce...", "options": ["Consumer wants", "Opportunity costs", "Output", "Resources"], "hint": "What is the actual THING that comes out at the end of the production process?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: C — Output</strong></p>\n<ul>\n<li>Producers combine land, labour, capital and enterprise (the factor inputs) to create output — the goods and services that get sold.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:afbb8356', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q14", "question": "Which of the following is a factor of production?", "options": ["A credit card", "A household''s washing machine", "A one pound coin", "A piece of spare land"], "hint": "Three of these belong to a household and are used for personal consumption, not production. Which one could actually be used by a business to produce something?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — A piece of spare land</strong></p>\n<ul>\n<li>Land is a factor of production.</li>\n<li>A credit card and a one pound coin are forms of money.</li>\n<li>A household''s washing machine is a consumer good, not capital used in production.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:c4ffcf01', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q16", "question": "Which of the following is an incorrect statement about consumers?", "options": ["Goods and services are bought for personal use", "They compare the satisfaction of consumption against the price when making a purchase", "They decide what goods and services will be produced", "They have little power in the market"], "hint": "This asks for the INCORRECT statement. Consumers influence production through demand, but do they directly decide what gets made?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — They decide what goods and services will be produced</strong></p>\n<ul>\n<li>This statement is incorrect: consumers influence production through their demand, but it is producers who decide what to actually supply.</li>\n<li>The other statements are correct: consumers buy for personal use, weigh up satisfaction against price, and often have little power in the market.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:fe78db17', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q17", "question": "Enterprise requires the individual concerned to organise the...", "options": ["Factors of production to minimise the opportunity cost", "Market for the factors of production", "Production and to bear the risks of the project", "Risk involved in borrowing the necessary finance"], "hint": "Enterprise is about combining the OTHER factors of production and taking on risk — which option describes exactly that?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — Production and to bear the risks of the project</strong></p>\n<ul>\n<li>Enterprise is the risk-taking that combines land, labour and capital to organise production.</li>\n<li>The entrepreneur bears the risk of the whole project — not just financing risk or minimising opportunity cost.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>The correct response to this question is Option C.</p>\n<p>Incorrect responses ranged across the other three options and indicated a common misunderstanding of what enterprise is.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:exam:503089fd', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'exam', 'mcq', 1, '{"num": "Q18", "question": "Which of the following refers to the role of the consumer?", "options": ["Acts as the end-user of a good or service", "Acts to protect buyers of goods and services", "Can decide what goods and services to supply", "Can introduce regulations about goods and services"], "hint": "Which option describes something the CONSUMER themselves does, rather than something the government does to protect or regulate them?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — Acts as the end-user of a good or service</strong></p>\n<ul>\n<li>Consumers are the end-users of goods and services.</li>\n<li>Protecting buyers, deciding what to supply and introducing regulations are roles of the government or producers, not consumers.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:mcq:d2c492ec', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'mcq', 'mcq', 1, '{"question": "A market stallholder selling fruit and vegetables is an example of a...", "options": ["Government body", "Consumer", "Producer", "Factor of production"]}'::jsonb, '{"answer": 2, "explain": "The stallholder supplies goods to customers, so they are a producer — producers range from a single market stall to a multinational company."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:mcq:3c3d68fd', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'mcq', 'mcq', 1, '{"question": "Which of these is the reward for the factor of production ''labour''?", "options": ["Interest", "Wages", "Rent", "Profit"]}'::jsonb, '{"answer": 1, "explain": "Labour is rewarded with wages, paid by the producer to the worker for their effort."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:mcq:1b596577', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'mcq', 'mcq', 1, '{"question": "Which of these is the reward for the factor of production ''land''?", "options": ["Interest", "Rent", "Wages", "Profit"]}'::jsonb, '{"answer": 1, "explain": "Land is rewarded with rent, paid to the owner of the land for allowing its use."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:mcq:fcf4c719', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'mcq', 'mcq', 1, '{"question": "Which of these is the reward for the factor of production ''enterprise''?", "options": ["Rent", "Wages", "Interest", "Profit"]}'::jsonb, '{"answer": 3, "explain": "Enterprise is rewarded with profit — what''s left over from revenue once every other cost has been paid, which is why it''s not guaranteed."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:mcq:190fa4c9', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'mcq', 'mcq', 1, '{"question": "A fleet of delivery vans owned by a courier company is an example of which factor of production?", "options": ["Labour", "Land", "Capital", "Enterprise"]}'::jsonb, '{"answer": 2, "explain": "Vans are a man-made aid to production, so they count as capital, not land or labour."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:mcq:2e7f7aa4', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'mcq', 'mcq', 1, '{"question": "Coal, farmland and fishing grounds are all examples of which factor of production?", "options": ["Labour", "Enterprise", "Land", "Capital"]}'::jsonb, '{"answer": 2, "explain": "These are all natural resources, so they fall under land — even coal, which is under the earth, still counts."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:mcq:88b05da5', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'mcq', 'mcq', 1, '{"question": "The skills, effort and health of the workforce are all part of which factor of production?", "options": ["Capital", "Enterprise", "Land", "Labour"]}'::jsonb, '{"answer": 3, "explain": "This describes labour — the human effort, physical and mental, used in production."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:mcq:336c1e36', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'mcq', 'mcq', 1, '{"question": "Which economic group raises most of its money through taxation, then spends it on public services?", "options": ["Entrepreneurs", "Producers", "The government", "Consumers"]}'::jsonb, '{"answer": 2, "explain": "The government collects tax revenue and uses it to fund services like the NHS and education, and to run the country."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:mcq:c5058c61', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'mcq', 'mcq', 1, '{"question": "Why did drink manufacturers reformulate their recipes to cut sugar after the UK sugar tax was introduced?", "options": ["To increase the price they could charge", "To reduce how much they paid their staff", "To avoid paying the tax on sugary drinks", "Because it was a legal requirement for all soft drinks"]}'::jsonb, '{"answer": 2, "explain": "The tax was based on sugar content, so cutting sugar let producers avoid or reduce the tax they had to pay — a good example of government policy affecting producer behaviour."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:mcq:4cab22df', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'mcq', 'mcq', 1, '{"question": "Which of the following best describes ''enterprise'' as a factor of production?", "options": ["The natural resources used in production", "The risk-taking that combines land, labour and capital", "The money used to start up a business", "The physical effort and skill of the workforce"]}'::jsonb, '{"answer": 1, "explain": "Enterprise is the risk-taking of the entrepreneur who organises the other three factors of production to create output."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tf:4ba98a12', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tf', 'tf', 1, '{"question": "Capital as a factor of production means the same thing as money."}'::jsonb, '{"answer": false, "explain": "Capital means the physical, man-made aids to production, like machinery and buildings — not money itself."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tf:f158b047', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tf', 'tf', 1, '{"question": "A sole trader buying stock for their shop is acting as a producer, not a consumer, in that transaction."}'::jsonb, '{"answer": true, "explain": "The purchase is for running the business, so it''s a producer action, even though the same person is a consumer in their personal life."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tf:87097d28', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tf', 'tf', 1, '{"question": "The government is not one of the three main economic groups."}'::jsonb, '{"answer": false, "explain": "The government IS one of the three main economic groups, alongside consumers and producers."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tf:3c9b597f', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tf', 'tf', 1, '{"question": "Enterprise is the risk-taking that combines land, labour and capital to create output."}'::jsonb, '{"answer": true, "explain": "That''s exactly what enterprise means — the entrepreneur organises the other three factors and takes on the risk."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tf:cd6f7634', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tf', 'tf', 1, '{"question": "The reward for labour is called interest."}'::jsonb, '{"answer": false, "explain": "The reward for labour is wages. Interest is the reward for capital."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tf:090522b4', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tf', 'tf', 1, '{"question": "Farmland, coal and fishing grounds are all examples of land as a factor of production."}'::jsonb, '{"answer": true, "explain": "All natural resources, whether on, under or above the earth, count as land."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tf:8cf2b7bd', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tf', 'tf', 1, '{"question": "Producers are always large companies."}'::jsonb, '{"answer": false, "explain": "A producer can be anyone who supplies a good or service, from a market stallholder to a multinational."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tf:e58df758', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tf', 'tf', 1, '{"question": "Because the three economic groups affect each other''s decisions, they are described as interdependent."}'::jsonb, '{"answer": true, "explain": "Correct — interdependence means one group''s actions have knock-on effects on the others."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:learn:7231b8e0', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'learn', 'mcq', 1, '{"readingTitle": "The three main economic groups", "reading": "<p>Every economy is made up of three main groups. Each plays a different role, but they all rely on each other.</p>\n<h4>Consumers</h4>\n<ul>\n<li>People who buy goods and services for their own personal use.</li>\n<li>The test is: <strong>is this purchase for personal use, or for running a business?</strong></li>\n<li>A hairdresser buying shampoo to use on customers is not acting as a consumer — that purchase is for the business.</li>\n</ul>\n<h4>Producers</h4>\n<ul>\n<li>Anyone who supplies goods or services — from a market stallholder to a multinational like Unilever.</li>\n<li>Producers take the factors of production and turn them into output (the finished good or service).</li>\n</ul>\n<h4>Government</h4>\n<ul>\n<li>Raises money mainly through taxes.</li>\n<li>Spends it on public services like the NHS and schools.</li>\n<li>Makes and enforces the rules everyone has to follow — like speed limits and health and safety law.</li>\n</ul>\n<h4>Interdependence — how the groups rely on each other</h4>\n<ul>\n<li><strong>Consumers ↔ producers:</strong> consumers buy what producers supply, and producers pay the wages that give consumers money to spend.</li>\n<li><strong>Government ↔ producers:</strong> government buys from firms, sets rules on things like working conditions, taxes business profits, and can subsidise industries it wants to support.</li>\n<li><strong>Government ↔ consumers:</strong> consumers pay taxes, and the government funds public services and passes laws that protect consumers.</li>\n</ul>\n<h4>Worked example: the UK sugar tax</h4>\n<ul>\n<li>The government is worried about child obesity…</li>\n<li>…so it puts a tax on producers of sugary drinks.</li>\n<li>Sugary drinks become more expensive to make.</li>\n<li>Producers change their recipes to cut sugar and avoid paying the tax.</li>\n<li>Consumers end up buying and drinking less sugar.</li>\n<li>Over time, the government may need to spend less on NHS treatment for obesity.</li>\n</ul>\n<p>One change touches all three groups — that is what interdependence means.</p>", "question": "A hairdresser buys a bottle of shampoo to use on customers in the salon. In this transaction, the hairdresser is acting as a...", "options": ["Consumer, because they are buying something", "Producer, because the purchase is for running the business", "None of the three economic groups", "Government, because they will charge VAT on it"]}'::jsonb, '{"answer": 1, "explain": "The test is whether the purchase is for personal use or for the business. Buying stock or supplies to run the business is a producer action, even though the hairdresser is personally a consumer in other parts of their life."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:learn:c6e28320', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'learn', 'mcq', 1, '{"readingTitle": "The factors of production", "reading": "<p>Producers need inputs to create their output. These inputs are called the <strong>factors of production</strong>, and there are four of them:</p>\n<table class=\"case-table\">\n<tr><th>Factor</th><th>What it covers</th><th>Reward for its use</th></tr>\n<tr><td><strong>Land</strong></td><td>All natural resources: farmland, oil, coal, minerals, fish stocks, forests</td><td>Rent</td></tr>\n<tr><td><strong>Labour</strong></td><td>The physical and mental effort of the workforce — their skills, qualifications and experience are sometimes called their <em>human capital</em></td><td>Wages</td></tr>\n<tr><td><strong>Capital</strong></td><td>Man-made aids to production: machinery, tools, factory buildings, vehicles, IT equipment (NOT money itself — see the misconception below)</td><td>Interest</td></tr>\n<tr><td><strong>Enterprise</strong></td><td>The risk-taking of the entrepreneur, who combines the other three factors to produce a good or service</td><td>Profit</td></tr>\n</table>\n<h4>Inputs become outputs</h4>\n<ul>\n<li>The factors of production are also called <strong>factor inputs</strong>.</li>\n<li>Producers combine them and add value, creating a new product — the <strong>factor output</strong>.</li>\n<li>Example: land (trees) + labour (carpenters) + capital (saws and machinery), organised by an entrepreneur''s enterprise, become a wooden table worth more than the raw inputs.</li>\n</ul>\n<h4>Why profit is different from the other rewards</h4>\n<ul>\n<li>Rent, wages and interest are agreed payments.</li>\n<li><strong>Profit is not guaranteed</strong> — it is what is left over once every other cost has been paid.</li>\n<li>A business can just as easily make a loss. That is why profit is the reward for taking a risk.</li>\n</ul>", "question": "What is the reward for the factor of production called capital?", "options": ["Interest", "Profit", "Rent", "Wages"]}'::jsonb, '{"answer": 0, "explain": "Capital earns interest — the payment made for the use of money-funded, man-made aids to production such as machinery and premises."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:misc:32265a1c', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Capital means money.</p><p><strong>✅ The correct idea:</strong> Capital means the physical, man-made aids to production — machinery, tools and factory buildings. Money used to buy those things is different from capital as a factor of production itself.</p>", "question": "A firm borrows £50,000 from the bank and uses it to buy a new delivery van. Which part of this is capital as a factor of production?", "options": ["The bank that lent the money", "The £50,000 loan itself", "The interest rate on the loan", "The delivery van"]}'::jsonb, '{"answer": 3, "explain": "The van is the man-made aid to production — that''s capital. The £50,000 is money used to buy it, not capital itself."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:misc:6f2094d0', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Producers are always big companies like supermarkets or manufacturers.</p><p><strong>✅ The correct idea:</strong> A producer is anyone who supplies a good or service — that includes a market stallholder, a self-employed hairdresser, or a one-person online business, not just large firms.</p>", "question": "A student sells hand-made friendship bracelets to classmates at breaktime. Are they a producer?", "options": ["No — only registered companies can be producers", "No — they are still a consumer while doing this", "Only if they make a profit", "Yes — they are supplying a good, however small the business"]}'::jsonb, '{"answer": 3, "explain": "Size doesn''t matter for the definition — anyone supplying a good or service is a producer."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:misc:eae405ac', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A business owner is always acting as a consumer.</p><p><strong>✅ The correct idea:</strong> A business owner is only a consumer when they buy something for personal use. When they buy stock or equipment for the business, they''re acting as a producer.</p>", "question": "A café owner buys a coffee machine for the café, and later buys a coffee machine as a birthday present for a friend. Which purchase makes them a consumer?", "options": ["Only the coffee machine bought as a gift", "Both purchases", "Only the coffee machine for the café", "Neither purchase"]}'::jsonb, '{"answer": 0, "explain": "The gift is for personal, non-business use, so that purchase is as a consumer. The café machine is for the business, so that''s a producer action."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:misc:e436bd63', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Profit is a guaranteed reward for running a business, just like wages are guaranteed for working.</p><p><strong>✅ The correct idea:</strong> Profit is not guaranteed — it''s what''s left over after all costs are paid, and a business can just as easily make a loss. That''s why profit is the reward for risk-taking (enterprise), unlike wages, which are agreed and paid whether or not the business does well.</p>", "question": "Why is profit described as the reward for enterprise rather than a guaranteed payment?", "options": ["Because it is paid before wages", "Because a business can make a loss instead of a profit", "Because it is set by the government", "Because only large firms can earn it"]}'::jsonb, '{"answer": 1, "explain": "Profit depends on revenue being higher than costs — it isn''t fixed or guaranteed like wages, rent or interest, which is exactly why it rewards risk."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tips:5fcb0a5f', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Explain'' questions (1-2 marks)", "reading": "<p>''Explain'' means state a definition or make a point — then develop it.</p>\n\n<p><strong>Structure for 2 marks:</strong></p>\n<ul>\n<li>Sentence 1 — state the term or point <strong>(1 mark)</strong></li>\n<li>Sentence 2 — develop it, or give the example if the question asks for one <strong>(1 mark)</strong></li>\n</ul>\n\n<p><strong>Worked example:</strong> \"Explain, using an example, what is meant by ''land''.\"</p>\n<ul>\n<li>\"Land is the factor of production covering natural resources\" (1 mark)</li>\n<li>\"…for example, farmland used to grow crops\" (1 mark)</li>\n</ul>\n\n<p><strong>The most common lost mark:</strong> forgetting the example when the question says \"using an example\".</p>\n\n<p>Real full-mark answers are only 1–2 sentences — about 25–45 words. Then stop.</p>", "question": "A question is worth 2 marks and starts with ''Explain, using an example...''. What must your answer include to get both marks?", "options": ["Just a long, detailed definition", "A diagram", "A definition AND a specific example", "Two separate definitions"]}'::jsonb, '{"answer": 2, "explain": "2-mark ''explain, using an example'' questions are usually split 1 mark for the definition/statement and 1 mark for a correct, specific example."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tips:f55a1f90', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — ''Evaluate'' questions (6 marks) — like the interdependence question", "reading": "<p>''Evaluate'' means explain + analyse + weigh up both sides + reach a judgement.</p>\n\n<p>Real full-mark answers are only about <strong>120–160 words</strong>. Longer is not better — focused is better.</p>\n\n<p><strong>Structure that scores 6/6 in real exams:</strong></p>\n<ul>\n<li><strong>Point:</strong> one way the groups depend on each other, applied to the case study — use the names and any data given</li>\n<li><strong>However:</strong> a limit to <em>that same point</em> — not a random new point</li>\n<li><strong>Overall:</strong> a judgement that answers \"the extent to which…\", with a reason</li>\n</ul>\n\n<p><strong>Sentence starters real top students use:</strong></p>\n<ul>\n<li>\"One reason is that…\"</li>\n<li>\"However, this depends on…\"</li>\n<li>\"On the other hand…\"</li>\n<li>\"Overall, … but …\"</li>\n</ul>\n\n<p><strong>Common mistake:</strong> a good point followed by an unrelated bad point is not evaluation.</p>\n\n<p>The \"However\" must be about the same point, and the judgement must give a reason — a judgement with no reason is capped at 5/6.</p>", "question": "In an ''Evaluate'' answer, what is a ''good point followed by a bad point that has no connection to it'' an example of?", "options": ["Good evaluation", "Analysis, but not application", "A diagram substitute", "Not evaluation at all — evaluation needs paired, connected points"]}'::jsonb, '{"answer": 3, "explain": "Real evaluation pairs an idea with a genuine limitation of THAT idea (or a contrasting factor it depends on) — two disconnected points don''t count as evaluation."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:tips:bf2b99d4', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'tips', 'mcq', 1, '{"readingTitle": "tip — Common exam angles for this topic", "reading": "<p>Based on real OCR papers, this topic keeps being tested in the same few ways:</p>\n\n<ul>\n<li>Classify a scenario as a consumer, producer or government action</li>\n<li>Match each factor of production to its reward (rent / wages / interest / profit)</li>\n<li>Spot the odd one out in a list mixing real factors of production with distractors like money or output</li>\n<li>A short \"explain\" question using the case study — apply the definition to the business in the text, don''t just repeat the textbook definition</li>\n<li>A 6-mark \"evaluate the extent of interdependence\" question, based on a case study</li>\n</ul>\n\n<p><strong>Watch out:</strong> questions asking \"NOT\" or \"incorrect\" flip the logic.</p>\n\n<p>Read them twice — the answer is the odd one out (often money, which students confuse with capital).</p>", "question": "A question asks: ''Which of the following is NOT a factor of production?'' What should you do first?", "options": ["Assume it''s a trick with no right answer", "Skip the question", "Pick the first correct-sounding factor of production", "Notice the word ''NOT'' and look for the one item that ISN''T a factor of production"]}'::jsonb, '{"answer": 3, "explain": "''NOT'' questions flip the usual logic — three options will be genuine factors of production and one will be the odd one out (often money, which is commonly confused with capital)."}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:fib:a0784847', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'fib', 'fib', 3, '{"question": "The three main economic groups are _____, _____ and the _____.", "blankOptions": {"B1": ["rent", "consumers", "enterprise", "profit"], "B2": ["capital", "producers", "land", "enterprise"], "B3": ["interest", "government", "profit", "rent"]}}'::jsonb, '{"blanks": {"B1": "consumers", "B2": "producers", "B3": "government"}}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:fib:48860c4d', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'fib', 'fib', 4, '{"question": "The four factors of production are _____, _____, _____ and _____.", "blankOptions": {"B1": ["government", "interest", "land", "rent"], "B2": ["rent", "consumers", "interdependent", "labour"], "B3": ["interest", "consumers", "capital", "profit"], "B4": ["consumers", "interest", "interdependent", "enterprise"]}}'::jsonb, '{"blanks": {"B1": "land", "B2": "labour", "B3": "capital", "B4": "enterprise"}}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:fib:99461f71', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'fib', 'fib', 4, '{"question": "The reward for land is _____, the reward for labour is _____, the reward for capital is _____ and the reward for enterprise is _____.", "blankOptions": {"B1": ["government", "rent", "labour", "capital"], "B2": ["government", "wages", "producers", "enterprise"], "B3": ["capital", "enterprise", "interest", "labour"], "B4": ["producers", "interdependent", "profit", "land"]}}'::jsonb, '{"blanks": {"B1": "rent", "B2": "wages", "B3": "interest", "B4": "profit"}}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:fib:958020d6', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'fib', 'fib', 1, '{"question": "Because the actions of the three economic groups affect each other, we say they are _____.", "blankOptions": {"B1": ["consumers", "government", "profit", "interdependent"]}}'::jsonb, '{"blanks": {"B1": "interdependent"}}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:9040c3f7', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consumer”?", "options": ["A person who buys goods or services for their own personal use", "An individual or organisation that supplies goods or services", "The reward paid to workers for their labour", "The value of a worker''s skills, qualifications and experience"]}'::jsonb, '{"answer": 0, "explain": "“Consumer” means: A person who buys goods or services for their own personal use"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:8aec484b', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Producer”?", "options": ["The risk-taking that combines land, labour and capital to create a good or service", "The reward paid to the owner of land for its use", "The value of a worker''s skills, qualifications and experience", "An individual or organisation that supplies goods or services"]}'::jsonb, '{"answer": 3, "explain": "“Producer” means: An individual or organisation that supplies goods or services"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:f909b461', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Government”?", "options": ["The reward paid for the use of capital", "The reward paid to workers for their labour", "The reward that goes to the entrepreneur for taking a risk", "Elected representatives who make laws, collect taxes and provide public services"]}'::jsonb, '{"answer": 3, "explain": "“Government” means: Elected representatives who make laws, collect taxes and provide public services"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:9f7a8af5', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Land”?", "options": ["Elected representatives who make laws, collect taxes and provide public services", "An individual or organisation that supplies goods or services", "Natural resources used in production, such as farmland, oil and fish stocks", "The reward that goes to the entrepreneur for taking a risk"]}'::jsonb, '{"answer": 2, "explain": "“Land” means: Natural resources used in production, such as farmland, oil and fish stocks"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:9d64f52d', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Labour”?", "options": ["An individual or organisation that supplies goods or services", "Elected representatives who make laws, collect taxes and provide public services", "The reward paid to workers for their labour", "The physical and mental effort of the workforce used in production"]}'::jsonb, '{"answer": 3, "explain": "“Labour” means: The physical and mental effort of the workforce used in production"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:0e4c77fe', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Capital”?", "options": ["The physical and mental effort of the workforce used in production", "The reward paid for the use of capital", "Man-made aids to production, such as machinery, tools and factory buildings", "The reward that goes to the entrepreneur for taking a risk"]}'::jsonb, '{"answer": 2, "explain": "“Capital” means: Man-made aids to production, such as machinery, tools and factory buildings"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:c960cdd4', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Enterprise”?", "options": ["The risk-taking that combines land, labour and capital to create a good or service", "The value of a worker''s skills, qualifications and experience", "A person who buys goods or services for their own personal use", "The reward paid for the use of capital"]}'::jsonb, '{"answer": 0, "explain": "“Enterprise” means: The risk-taking that combines land, labour and capital to create a good or service"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:b06f979d', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Rent”?", "options": ["Natural resources used in production, such as farmland, oil and fish stocks", "The reward that goes to the entrepreneur for taking a risk", "Man-made aids to production, such as machinery, tools and factory buildings", "The reward paid to the owner of land for its use"]}'::jsonb, '{"answer": 3, "explain": "“Rent” means: The reward paid to the owner of land for its use"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:e6981e6c', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Wages”?", "options": ["Elected representatives who make laws, collect taxes and provide public services", "An individual or organisation that supplies goods or services", "Natural resources used in production, such as farmland, oil and fish stocks", "The reward paid to workers for their labour"]}'::jsonb, '{"answer": 3, "explain": "“Wages” means: The reward paid to workers for their labour"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:73269673', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Interest”?", "options": ["The reward that goes to the entrepreneur for taking a risk", "Natural resources used in production, such as farmland, oil and fish stocks", "A person who buys goods or services for their own personal use", "The reward paid for the use of capital"]}'::jsonb, '{"answer": 3, "explain": "“Interest” means: The reward paid for the use of capital"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:9040d8b4', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Profit”?", "options": ["Elected representatives who make laws, collect taxes and provide public services", "The reward that goes to the entrepreneur for taking a risk", "Man-made aids to production, such as machinery, tools and factory buildings", "The risk-taking that combines land, labour and capital to create a good or service"]}'::jsonb, '{"answer": 1, "explain": "“Profit” means: The reward that goes to the entrepreneur for taking a risk"}'::jsonb),
('economics:1-1-main-economic-groups-and-factors-of-production:match:402cf14d', 'economics', 'economics:1-1-main-economic-groups-and-factors-of-production', '1.1 Main Economic Groups and Factors of Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Human capital”?", "options": ["The reward paid to workers for their labour", "The value of a worker''s skills, qualifications and experience", "The reward paid for the use of capital", "The risk-taking that combines land, labour and capital to create a good or service"]}'::jsonb, '{"answer": 1, "explain": "“Human capital” means: The value of a worker''s skills, qualifications and experience"}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:1914a3dc', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q2", "question": "An opportunity cost of a car manufacturing firm deciding to increase its labour force would be...", "options": ["The benefits of increasing the size of its labour force", "The benefits that could have been received by investing in machinery", "The increase in the amount of profit made by the firm", "The increase in the amount spent on wages"], "hint": "Opportunity cost is the benefit of the NEXT BEST ALTERNATIVE given up — not the cost of the option chosen, and not its benefits.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — The benefits that could have been received by investing in machinery</strong></p>\n<ul>\n<li>Opportunity cost is the benefit of the next best alternative given up.</li>\n<li>The money spent on extra workers could have bought machinery instead — the machinery''s benefits are what''s sacrificed.</li>\n<li>Wages (D) are the money cost of the choice, not the opportunity cost.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:6259ed03', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q4", "question": "What is the key economic question?", "options": ["Are the needs of health more than the wants of education?", "For whom should health be produced?", "How should health be produced?", "What should be produced?"], "caseStudy": "The government allocates scarce resources between many uses. When they decide to spend more money on health instead of education, the government is answering a key economic question.", "hint": "The three key questions are WHAT, HOW and FOR WHOM. Choosing health over education is a decision about which one?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: D — What should be produced?</strong></p>\n<ul>\n<li>Choosing to put resources into health instead of education is deciding WHAT gets produced with the scarce budget.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Only a few candidates have the correct answer D, showing that the concept of ''key economic question'' is not well understood.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:6c890353', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q5", "question": "This is an example of...", "options": ["Gross pay", "Market forces", "Opportunity cost", "The economic problem"], "caseStudy": "A shop owner decides to close their shop for two weeks to go on holiday. As a result, they will lose £2000 in revenue.", "hint": "The £2000 is what the owner GIVES UP by choosing the holiday — what concept is that?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — Opportunity cost</strong></p>\n<ul>\n<li>The £2000 of revenue is the next best alternative given up by choosing the holiday — a textbook opportunity cost.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Most of the candidates gave C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:419a9cb0', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q6", "question": "What is meant by scarce resources?", "options": ["Economic choice means that resources are used in the best way possible", "Resources must not be overused so they can be replaced", "The existence of finite resources and the need to choose between uses", "Where there are insufficient resources to satisfy all wants"], "hint": "Scarcity is about there not being ENOUGH to satisfy ALL wants — be careful, one of the wrong options describes sustainability instead.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — Where there are insufficient resources to satisfy all wants</strong></p>\n<ul>\n<li>Scarcity means there is not enough of a resource to satisfy all wants.</li>\n<li>Option B describes sustainability, not scarcity — a common mix-up.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Most candidates gave the correct answer D, but too many lacked understanding of scarcity, with many choosing C.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:c8a44407', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q7", "question": "This is an example of which type of sustainability?", "options": ["Economic", "Environmental", "Renewable", "Social"], "caseStudy": "The government has decided to rebuild the main road near Carwod, as the present road is too dangerous. The new road will be nearer to the village of Carwod.", "hint": "The reason for the project is SAFETY and convenience for the villagers — which sustainability is about quality of life?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — Social</strong></p>\n<ul>\n<li>Rebuilding a dangerous road improves the community''s safety and quality of life — that is social sustainability.</li>\n<li>''Renewable'' is not a type of sustainability at all.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:6c890353-2', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q10", "question": "This is an example of...", "options": ["Economies of scale", "Oligopoly collusion", "Scarce resources", "Unlimited wants"], "caseStudy": "For most of 2021 the world supply of computer chips did not satisfy the demand for them.", "hint": "Not enough supply to satisfy demand = not enough of the resource to go around. Which term is that?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — Scarce resources</strong></p>\n<ul>\n<li>There was not enough supply of chips to satisfy demand — the definition of a scarce resource.</li>\n<li>''Unlimited wants'' (D) describes the demand side in general, but the situation described is the shortage itself.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>The correct response to this question was Option C; however, many candidates gave Option D as the correct response.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:4d170941', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q13", "question": "Opportunity cost can be defined as...", "options": ["The loss as a result of missing a bargain", "The minimum average cost of producing a good", "The price of a good or service", "The sacrifice of the most desired alternative"], "hint": "Look for the option about SACRIFICING an ALTERNATIVE — not about prices or production costs.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — The sacrifice of the most desired alternative</strong></p>\n<ul>\n<li>Opportunity cost is what you give up — the next best alternative sacrificed when a choice is made.</li>\n<li>It is not a price, a production cost, or a missed bargain.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:3cf21e3e', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q14", "question": "A feature of an efficient market is that...", "options": ["Any costs of environmental damage are met equally by all consumers", "Firms are unable to make any profit", "The prices of products are set at a level that all consumers can afford", "The prices of products reflect the worth of resources used in their production"], "hint": "In an efficient market, what should prices actually TELL you about the product?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — The prices of products reflect the worth of resources used in their production</strong></p>\n<ul>\n<li>In an efficient market, prices signal the true value of the scarce resources used up in making the product.</li>\n<li>Efficiency does not mean everyone can afford everything, or that firms make no profit.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:46b0a6de', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q16", "question": "This means that when something is produced...", "options": ["An identical alternative is given up", "The least valuable alternative is given up", "The next best alternative is given up", "There is no other alternative"], "caseStudy": "All production decisions have an opportunity cost.", "hint": "The definition always says the NEXT BEST alternative — not identical, not least valuable.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — The next best alternative is given up</strong></p>\n<ul>\n<li>Opportunity cost is always the NEXT BEST alternative foregone — that exact phrase is what mark schemes look for.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:a5465a25', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q17", "question": "Which of the following is not a scarce resource?", "options": ["Air", "Buildings", "Labour", "Machinery"], "hint": "A resource is scarce when there isn''t enough to satisfy all wants. Which one is there (basically) an unlimited free supply of?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: A — Air</strong></p>\n<ul>\n<li>Air is freely available to everyone — there is enough to satisfy all wants, so it is not scarce.</li>\n<li>Buildings, labour and machinery are all limited and have competing uses.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:6e2f873e', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q20", "question": "A market system allocates scarce resources through...", "options": ["Government taxes and subsidies", "Prices and incentives", "The allocation of state benefit payments", "The control of wages"], "hint": "In a MARKET system (not a planned one), what guides producers and consumers to decide where resources go?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — Prices and incentives</strong></p>\n<ul>\n<li>In a market system, rising and falling prices act as signals and incentives that direct resources to where they are most wanted.</li>\n<li>Taxes, subsidies and benefits are government tools — they belong to the planned/intervention side of the spectrum.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:exam:c56bc23c', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'exam', 'mcq', 1, '{"num": "Q21", "question": "What is meant by unlimited wants?", "options": ["Goods which do not have an opportunity cost", "Resources which are essential for survival", "The ability to buy whatever is required", "The infinite desire for goods and services"], "hint": "''Unlimited'' = infinite. Which option is about desire that never ends?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — The infinite desire for goods and services</strong></p>\n<ul>\n<li>Unlimited wants means people''s desire for goods and services has no end.</li>\n<li>Resources essential for survival (B) describes needs, not wants.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:1-2-the-basic-economic-problem:mcq:d23b4c48', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'mcq', 'mcq', 1, '{"question": "Which of these best describes the basic economic problem?", "options": ["Prices are always rising", "Governments spend too much money", "Some countries are richer than others", "Unlimited wants but scarce resources"]}'::jsonb, '{"answer": 3, "explain": "The basic economic problem is that resources are limited (scarce) while wants are unlimited — so choices have to be made."}'::jsonb),
('economics:1-2-the-basic-economic-problem:mcq:f26b28c8', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'mcq', 'mcq', 1, '{"question": "Warm clothing, food and shelter are examples of...", "options": ["Luxuries", "Wants", "Needs", "Scarce resources"]}'::jsonb, '{"answer": 2, "explain": "These are needs — the minimum required to survive. Everything beyond them is a want."}'::jsonb),
('economics:1-2-the-basic-economic-problem:mcq:55e1a613', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'mcq', 'mcq', 1, '{"question": "Why are wants described as ''unlimited''?", "options": ["Because wants never change over time", "Because people always desire more goods and services than they can have", "Because everyone wants the same things", "Because all wants are essential for survival"]}'::jsonb, '{"answer": 1, "explain": "There is no end to what people would like to have — as soon as one want is satisfied, another appears, and new products create new wants."}'::jsonb),
('economics:1-2-the-basic-economic-problem:mcq:dc276ee0', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'mcq', 'mcq', 1, '{"question": "The three key questions every economy must answer are: what to produce, how to produce it, and...", "options": ["When to produce it", "Where to produce it", "Why to produce it", "For whom to produce it"]}'::jsonb, '{"answer": 3, "explain": "The three questions are what, how, and for whom goods and services should be produced."}'::jsonb),
('economics:1-2-the-basic-economic-problem:mcq:74eb3108', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'mcq', 'mcq', 1, '{"question": "In a market economy, resources are allocated by...", "options": ["International organisations", "The forces of demand and supply", "The government", "A vote among consumers"]}'::jsonb, '{"answer": 1, "explain": "In a market economy, prices set by demand and supply act as signals and incentives that decide where resources go."}'::jsonb),
('economics:1-2-the-basic-economic-problem:mcq:8390392c', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'mcq', 'mcq', 1, '{"question": "The UK is best described as which type of economy?", "options": ["A barter economy", "A mixed economy", "A pure free market economy", "A planned economy"]}'::jsonb, '{"answer": 1, "explain": "The UK leans market-based but the government intervenes in areas like health and education — so it''s a mixed economy, like every real country."}'::jsonb),
('economics:1-2-the-basic-economic-problem:mcq:a8110800', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'mcq', 'mcq', 1, '{"question": "A student has £5 and buys a cinema ticket instead of a pizza. The opportunity cost is...", "options": ["The £5 spent", "The pizza given up", "The cinema ticket", "Both the ticket and the pizza"]}'::jsonb, '{"answer": 1, "explain": "Opportunity cost is the next best alternative given up. The scarce resource (£5) forced a choice, and the pizza is what was sacrificed."}'::jsonb),
('economics:1-2-the-basic-economic-problem:mcq:e8c34a6c', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'mcq', 'mcq', 1, '{"question": "The government increases spending on the NHS, which means less money for road building. This shows that government choices...", "options": ["Have no opportunity cost", "Only affect producers", "Involve an opportunity cost", "Always make everyone better off"]}'::jsonb, '{"answer": 2, "explain": "The budget is a scarce resource — more for one area means less for another. The roads given up are the opportunity cost of the extra NHS spending."}'::jsonb),
('economics:1-2-the-basic-economic-problem:mcq:731749c5', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'mcq', 'mcq', 1, '{"question": "A new bypass improves residents'' quality of life but cost £50 million that could have been spent elsewhere. Which TWO ideas does this show?", "options": ["Social sustainability and opportunity cost", "Environmental sustainability and profit", "Needs and the product market", "Unlimited wants and specialisation"]}'::jsonb, '{"answer": 0, "explain": "Better quality of life = social sustainability; the £50 million given up from other uses = opportunity cost."}'::jsonb),
('economics:1-2-the-basic-economic-problem:mcq:9830c70c', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'mcq', 'mcq', 1, '{"question": "Which of these is a question about ENVIRONMENTAL sustainability?", "options": ["Will the project make a profit?", "Is the project fair to all taxpayers?", "Will the project create jobs?", "Are renewable resources being used at a rate they can be replaced?"]}'::jsonb, '{"answer": 3, "explain": "Environmental sustainability is about the impact on the environment — resource use and pollution. Jobs and growth are economic; fairness and quality of life are social."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tf:a06a5ff5', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tf', 'tf', 1, '{"question": "In economics, a mobile phone is classed as a need."}'::jsonb, '{"answer": false, "explain": "A phone might feel essential, but needs are only the things required for basic survival — a phone is a want."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tf:b8d1a783', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tf', 'tf', 1, '{"question": "Wants are unlimited."}'::jsonb, '{"answer": true, "explain": "People always desire more goods and services — as tastes and technology change, new wants keep appearing."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tf:901608ed', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tf', 'tf', 1, '{"question": "The UK is a pure free market economy."}'::jsonb, '{"answer": false, "explain": "The UK is a mixed economy — it leans market-based, but the government intervenes in areas like health, education and defence."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tf:328bcc20', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tf', 'tf', 1, '{"question": "Opportunity cost only applies to decisions about money."}'::jsonb, '{"answer": false, "explain": "Opportunity cost exists wherever any scarce resource forces a choice — money, time, land, labour or capital."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tf:16c6a548', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tf', 'tf', 1, '{"question": "The basic economic problem exists because resources are limited but wants are not."}'::jsonb, '{"answer": true, "explain": "That''s exactly it — finite resources meeting unlimited wants creates scarcity, so choices must be made."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tf:2a3936ac', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tf', 'tf', 1, '{"question": "In a planned economy, resources are allocated by the state."}'::jsonb, '{"answer": true, "explain": "Correct — in a planned economy the state decides what, how and for whom to produce, instead of market forces."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tf:b4c29755', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tf', 'tf', 1, '{"question": "Social sustainability is about a decision''s impact on a community''s quality of life and whether it is fair for everyone."}'::jsonb, '{"answer": true, "explain": "That''s the definition — economic sustainability covers growth and resources, environmental covers pollution and resource use."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tf:4e8da081', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tf', 'tf', 1, '{"question": "If the government spends more on education, there is no opportunity cost because education is a need."}'::jsonb, '{"answer": false, "explain": "Every choice has an opportunity cost — money spent on education can''t be spent on something else, however worthwhile education is."}'::jsonb),
('economics:1-2-the-basic-economic-problem:learn:0e4e58cd', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'learn', 'mcq', 1, '{"readingTitle": "Needs, wants and scarce resources", "reading": "<h4>Needs</h4>\n<ul>\n<li>The things required to survive — food, water, shelter, warmth, basic clothing.</li>\n<li>Imagine packing for a 3-day camping trip with limited car space: a tent, warm clothes, food and water, and a first aid kit are needs.</li>\n</ul>\n<h4>Wants</h4>\n<ul>\n<li>Everything beyond basic survival — and wants are effectively <strong>unlimited</strong>.</li>\n<li>A phone might feel essential to you, but in economics it is a want, because it goes beyond basic survival needs.</li>\n<li>Wants also change over time as tastes, fashion and technology change — 20 years ago no one \"wanted\" a smartphone, because it didn''t exist.</li>\n</ul>\n<h4>Scarce resources</h4>\n<ul>\n<li>Resources — land, labour, capital and enterprise — are <strong>finite</strong>: there is only a limited amount of them.</li>\n<li>A resource is scarce when there is not enough of it to satisfy all wants.</li>\n<li>Scarcity applies at every stage of production. A pair of trainers needs leather, cotton and rubber (land), plus labour and capital to make, market and deliver it.</li>\n</ul>", "question": "In economics, which of the following is classed as a NEED?", "options": ["A holiday", "Shelter", "Branded trainers", "A mobile phone"]}'::jsonb, '{"answer": 1, "explain": "Needs are the things required to survive — food, water, shelter, warmth and basic clothing. Everything beyond that, including a phone, is a want."}'::jsonb),
('economics:1-2-the-basic-economic-problem:learn:aebff8d6', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'learn', 'mcq', 1, '{"readingTitle": "The basic economic problem and the three questions", "reading": "<h4>The basic economic problem</h4>\n<ul>\n<li>Wants are <strong>unlimited</strong>, but the resources available to supply them are <strong>scarce</strong>.</li>\n<li>So the basic economic problem is: <strong>how do we best satisfy society''s unlimited wants using limited resources?</strong></li>\n<li>Because of scarcity, <strong>choices</strong> have to be made about how to use resources — and every choice has an opportunity cost.</li>\n</ul>\n<h4>The three questions every economy must answer</h4>\n<ul>\n<li><strong>What</strong> should be produced?</li>\n<li><strong>How</strong> should it be produced?</li>\n<li><strong>For whom</strong> should it be produced?</li>\n</ul>\n<h4>Types of economy — a spectrum, not a label</h4>\n<ul>\n<li><strong>Market economy:</strong> resources allocated by the market forces of demand and supply — prices and incentives guide producers.</li>\n<li><strong>Planned economy:</strong> resources allocated by the state.</li>\n<li><strong>Mixed economy:</strong> a combination of both — and in reality, <strong>every real country is a mixed economy</strong>, sitting somewhere on the spectrum between the two extremes.</li>\n<li>The UK leans market-based, but the government still intervenes (NHS, schools, defence). China is largely state-controlled, but has many private businesses.</li>\n</ul>\n<h4>How the UK''s mixed economy answers the three questions</h4>\n<ul>\n<li><strong>What:</strong> mostly whatever is profitable — success gives firms more resources to keep producing. But the government steps in for things society needs, like health, education and defence.</li>\n<li><strong>How:</strong> competition pushes firms to produce efficiently and keep costs down, while the government enforces product standards and health and safety rules.</li>\n<li><strong>For whom:</strong> mainly \"user pays\" — goods go to those who can afford them — but taxes and benefits redistribute money to those in need, and some services (like the NHS) are free to use.</li>\n</ul>", "question": "The government decides to spend more money on health instead of education. Which of the three key economic questions is it answering?", "options": ["What should be produced?", "How should it be produced?", "For whom should it be produced?", "Where should it be produced?"]}'::jsonb, '{"answer": 0, "explain": "Choosing to put resources into health rather than education is deciding WHAT gets produced. (This exact scenario appeared as a real OCR exam question — and only a few candidates got it right.)"}'::jsonb),
('economics:1-2-the-basic-economic-problem:learn:27366e39', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'learn', 'mcq', 1, '{"readingTitle": "Opportunity cost", "reading": "<h4>The definition</h4>\n<ul>\n<li><strong>Opportunity cost is the next best alternative given up when making a choice.</strong></li>\n<li>It exists because resources are scarce — if you could have everything, nothing would need to be given up.</li>\n</ul>\n<h4>The crucial exam skill: link it to the scarce resource</h4>\n<ul>\n<li>Weak answer: \"If I buy a drink instead of a chocolate bar, the chocolate is the opportunity cost.\"</li>\n<li>Strong answer: \"I want both, but I only have enough <strong>money</strong> for one — so buying the drink means the chocolate is the opportunity cost.\"</li>\n<li>The scarce resource is usually money, but it can be time, land, labour or capital.</li>\n</ul>\n<h4>Opportunity cost applies to every economic group</h4>\n<ul>\n<li><strong>Consumers:</strong> spending now means giving up the interest you could have earned by saving.</li>\n<li><strong>Producers:</strong> a firm that can afford new machinery OR a new outlet, but not both, gives up one to get the other.</li>\n<li><strong>Government:</strong> spending more on education means less for something else in the budget — or a bigger deficit, which has to be repaid later with interest.</li>\n</ul>\n<h4>Related ideas: trade-offs and satisfaction</h4>\n<ul>\n<li>People choose the option that gives them the most satisfaction (economists call this <em>utility</em>) for the money they have available.</li>\n<li>A <strong>trade-off</strong> is choosing one option above all the alternatives — opportunity cost measures the benefit lost from the next best one.</li>\n</ul>", "question": "A firm can afford to buy new machinery OR open a new outlet, but not both. It chooses the machinery. What is the opportunity cost?", "options": ["The benefit it would have got from the new outlet", "The profit made from the machinery", "The price paid for the machinery", "There is no opportunity cost for firms"]}'::jsonb, '{"answer": 0, "explain": "Opportunity cost is the benefit of the next best alternative given up — here, what the new outlet would have brought in. It is not the money paid for the option you chose."}'::jsonb),
('economics:1-2-the-basic-economic-problem:learn:e075cc18', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'learn', 'mcq', 1, '{"readingTitle": "Evaluating economic choices: the three sustainabilities", "reading": "<p>Every economic choice has costs and benefits. The exam wants you to weigh them up using three types of <strong>sustainability</strong>:</p>\n<h4>1. Economic sustainability</h4>\n<ul>\n<li>Is this the best use of scarce resources so that growth can continue over time?</li>\n<li>Think: costs now and in the future, jobs created, effect on employment and growth.</li>\n</ul>\n<h4>2. Social sustainability</h4>\n<ul>\n<li>How does the choice affect people''s <strong>quality of life</strong> — and is it <strong>fair for everyone</strong>, now and in the future?</li>\n</ul>\n<h4>3. Environmental sustainability</h4>\n<ul>\n<li>The impact on the environment: are renewable resources used at a rate they can be replaced, are non-renewable resources used efficiently, and what happens to pollution?</li>\n</ul>\n<h4>Worked example: the Elizabeth line (Crossrail)</h4>\n<ul>\n<li><strong>Economic:</strong> cost over £19 billion (a big opportunity cost) and hurt some businesses during construction — but created thousands of construction jobs and made it easier for workers to travel.</li>\n<li><strong>Social:</strong> easier commuting and less congestion — but people near the works were disturbed for years, and it is funded by national taxes while the benefits mostly go to London. Is that fair?</li>\n<li><strong>Environmental:</strong> may cut road traffic and pollution — but tunnelling used enormous amounts of energy, and more people might simply choose to travel more.</li>\n</ul>\n<p><strong>Exam practice idea:</strong> apply the same three-way framework to HS2 or a third runway at Heathrow — sustainability questions often use an unfamiliar case study, and this structure works on any of them.</p>", "question": "The government rebuilds a dangerous main road so it is safer and closer to a village. Which type of sustainability is this an example of?", "options": ["Social", "Environmental", "Renewable", "Economic"]}'::jsonb, '{"answer": 0, "explain": "Making the road safer and closer improves the community''s quality of life — that is social sustainability. (This is a real OCR exam question; ''renewable'' isn''t a type of sustainability at all.)"}'::jsonb),
('economics:1-2-the-basic-economic-problem:misc:1624d2ef', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Needs'' and ''wants'' mean the same thing, so it doesn''t matter which word I use.</p><p><strong>✅ The correct idea:</strong> Examiners want the distinction stated explicitly: needs are required for survival (food, water, shelter, warmth); wants are everything beyond that — and wants are unlimited. Mixing the words up costs marks in definition questions.</p>", "question": "Which sentence uses the terms correctly?", "options": ["\"Water is a want because people enjoy drinking it\"", "\"Everyone needs a games console\"", "\"Shelter is a need; a bigger house in a nicer area is a want\"", "\"Needs are unlimited but wants are scarce\""]}'::jsonb, '{"answer": 2, "explain": "Shelter is required for survival (a need); upgrading beyond that is desire (a want). And it''s WANTS that are unlimited, while RESOURCES are scarce."}'::jsonb),
('economics:1-2-the-basic-economic-problem:misc:ea32846c', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The UK is a free market economy and China is a planned economy.</p><p><strong>✅ The correct idea:</strong> Both are mixed economies. The UK leans market-based but the government intervenes (NHS, schools, defence); China is largely state-controlled but has many private businesses. The exam skill is placing countries on a SPECTRUM between the two extremes, not labelling them as pure opposites.</p>", "question": "What is the most accurate way to describe the UK and China?", "options": ["Both are mixed economies at different points on the market–planned spectrum", "Neither has any government intervention", "The UK is purely free market; China is purely planned", "Both are planned economies"]}'::jsonb, '{"answer": 0, "explain": "No real country is a pure example of either extreme — both the UK and China combine market forces with state intervention, just in different proportions."}'::jsonb),
('economics:1-2-the-basic-economic-problem:misc:0c79bea6', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For opportunity cost, it''s enough to say: ''I bought a drink instead of a chocolate bar, so the chocolate is the opportunity cost.''</p><p><strong>✅ The correct idea:</strong> That answer misses the link to the SCARCE RESOURCE that forced the choice, and mark schemes also refuse the definition mark when ''given up'' or ''foregone'' is missing. Level 0 answer: \"Opportunity cost is the cost of an opportunity.\" Level 1 answer: the drink/chocolate sentence above. Full-marks answer: \"I want both, but I only have enough MONEY for one — so buying the drink means giving up the chocolate, which is the opportunity cost.\" The difference: the good answer names the scarce resource and uses ''giving up''.</p>", "question": "A 2-mark question says: \"Using an example from Extract 2, explain what is meant by opportunity cost.\" What earns full marks?", "options": ["Just naming an example from Extract 2", "A perfect textbook definition on its own", "A definition plus any example you can think of", "A definition plus an example taken from Extract 2"]}'::jsonb, '{"answer": 3, "explain": "The real OCR mark scheme gave no reward for a purely theoretical answer or for examples not from the extract — you need the definition AND an example from the source given."}'::jsonb),
('economics:1-2-the-basic-economic-problem:misc:09d76160', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The factor market is the same as the primary sector, and the product market is the same as the secondary/tertiary sector.</p><p><strong>✅ The correct idea:</strong> These are different ideas. The FACTOR market is where factors of production (like labour) are bought and sold — a farmer hiring workers is in the factor market. The PRODUCT market is where finished goods and services are sold to consumers. Sectors (primary/secondary/tertiary) describe types of production, not markets. This confusion comes straight from a real OCR examiner report — most candidates mixed them up.</p>", "question": "A farmer hires two extra fruit pickers. Which market is this happening in?", "options": ["The factor market", "The stock market", "The product market", "The primary sector market"]}'::jsonb, '{"answer": 0, "explain": "Hiring workers is buying labour — a factor of production — so it happens in the factor market. Selling the fruit to shoppers would happen in the product market."}'::jsonb),
('economics:1-2-the-basic-economic-problem:misc:0e2ccd24', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Elon Musk\" or \"Amazon\" is a good example of enterprise.</p><p><strong>✅ The correct idea:</strong> Enterprise is the factor of production that takes a RISK in organising the other factors — so the example must show the risk-taking activity, not just name a famous person or company. Level 0 answer: \"Elon Musk.\" Level 1 answer: \"Enterprise is taking a risk to organise production\" (definition, no example). Full-marks answer: \"Enterprise is the factor that takes a risk organising the other factors of production — for example, borrowing £500,000 to set up a hotel.\" This comes from a real examiner report: naming Musk, Gates or Amazon without showing the enterprise activity earned no example mark.</p>", "question": "Which of these would earn the example mark for ''enterprise''?", "options": ["\"Taking the risk of setting up a new coffee shop\"", "\"Amazon is a big company\"", "\"Jeff Bezos\"", "\"Enterprise means being enterprising\""]}'::jsonb, '{"answer": 0, "explain": "The example must show risk-taking and organising factors of production in action. Naming a person or company on its own shows nothing about enterprise itself."}'::jsonb),
('economics:1-2-the-basic-economic-problem:misc:6a2f8e56', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Economic, social and environmental sustainability are basically the same thing, so any of them can be used in an answer.</p><p><strong>✅ The correct idea:</strong> They are three different tests, and the exam names WHICH one it wants. Economic = best use of resources for growth over time. Social = quality of life and fairness. Environmental = resource use and pollution. In a real exam, candidates asked about ECONOMIC sustainability who wrote about the environment scored poorly — the examiner report says you must be able to clearly tell them apart.</p>", "question": "A question asks about the effect of a choice on a café''s ECONOMIC sustainability. Which point is on-topic?", "options": ["The café''s carbon footprint will fall", "The loan repayments may leave too little money for the business to keep growing", "The café''s new furniture is made from recycled wood", "The village will look prettier"]}'::jsonb, '{"answer": 1, "explain": "Economic sustainability is about whether the choice lets the business keep using its resources to grow over time — loans, costs and revenue. Recycling and carbon are environmental; village appearance is social."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tips:8622f527', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tips', 'mcq', 1, '{"readingTitle": "explain — 2-mark questions: from 0 to full marks", "reading": "<p>Here is the same answer to <em>\"Explain, using an example, what is meant by ''opportunity cost''\"</em> at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"Opportunity cost is the cost of an opportunity.\"</p>\n<ul>\n<li>This just repeats the question in different words (examiners call it a tautology). No economics shown.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"Opportunity cost is the next best alternative you give up when making a choice.\"</p>\n<ul>\n<li>A correct definition — but the question said \"using an example\" and there isn''t one. The second mark is gone.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"Opportunity cost is the next best alternative given up when making a choice. For example, a farmer who uses his land to grow beans gives up the chance to grow other crops on it.\"</p>\n<ul>\n<li>Definition (1 mark) + a specific example (1 mark). Two sentences. Done.</li>\n</ul>\n\n<p><strong>Extra traps from real mark schemes:</strong></p>\n<ul>\n<li>Leaving out \"given up\" / \"foregone\" from the definition loses the definition mark.</li>\n<li>If the question says \"using an example <em>from Extract 2</em>\", an example from anywhere else scores nothing.</li>\n</ul>", "question": "Why does a perfect definition with no example only score 1 out of 2 when the question says ''using an example''?", "options": ["Because the second mark is specifically for the example the question asked for", "Because definitions never earn marks", "Because examples always come first", "Because the answer is too short"]}'::jsonb, '{"answer": 0, "explain": "The 2 marks are split: 1 for the definition, 1 for the example. Miss the example and that mark is simply unavailable — this is the single most common way students drop marks on 2-markers."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tips:acfeb9d6', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tips', 'mcq', 1, '{"readingTitle": "tip — Calculation questions: from 0 to full marks", "reading": "<p>This topic''s real exam paper had THREE calculation questions. Here''s the ladder, using <em>\"Calculate the average cost of destroying the Asian Hornet in France, Italy and the UK\"</em> (£10.5m + £8m + £7.6m):</p>\n\n<p><strong>❌ 0 marks:</strong> \"£12m\" (wrong answer, no working shown)</p>\n<ul>\n<li>With no working, a wrong answer has nothing to rescue it.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"£8.7\"</p>\n<ul>\n<li>The maths is right but the units are missing — real candidates lost a mark for writing 8.7 and forgetting the <strong>million</strong>.</li>\n<li>Also 1 mark: stopping at £26.1m (added but didn''t divide by 3).</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"£10.5m + £8m + £7.6m = £26.1m. £26.1m ÷ 3 = <strong>£8.7 million</strong>\"</p>\n\n<p><strong>Two safety nets to remember:</strong></p>\n<ul>\n<li><strong>Always show working.</strong> Under the Own Figure Rule (OFR), if you make a slip early but your method afterwards is correct, you can still get a mark.</li>\n<li><strong>Always write the units</strong> — £, %, million. The number alone is not the answer.</li>\n</ul>", "question": "A student''s first step in a calculation is wrong, but they carry the wrong number through the correct method. What happens under the Own Figure Rule?", "options": ["They can still earn a mark for the correct method", "The examiner corrects the first step for them", "They get full marks anyway", "They score 0 — the answer is wrong"]}'::jsonb, '{"answer": 0, "explain": "OFR protects the method: a slip early on doesn''t wipe out everything after it — but only if the working is on the page. That''s why you always show working."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tips:841283f6', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — 6-mark ''Evaluate'' questions: from Level 0 to Level 3", "reading": "<p>Using the real question <em>\"Evaluate the costs of the economic choices that Nina and Leo must make on their economic sustainability\"</em>:</p>\n\n<p><strong>❌ Level 0 (0 marks):</strong> writes about how the café should recycle and cut its carbon footprint.</p>\n<ul>\n<li>That''s ENVIRONMENTAL sustainability. The question asked about ECONOMIC sustainability. Real candidates did exactly this and scored nothing.</li>\n</ul>\n\n<p><strong>⚠️ Level 1 (1–2 marks):</strong> \"The £10,000 loan must be repaid within a year with interest that could rise from 2.5% to 3.5%, which means less money for running the café, which could stop it growing.\"</p>\n<ul>\n<li>Good analysis — but no other side, no weighing up, no judgement. The examiner''s report says candidates with strong analysis but zero evaluation could not get more than 1 mark out of 6.</li>\n</ul>\n\n<p><strong>⚠️ Level 2 (3–4 marks):</strong> the same analysis, plus \"However, the improvements might attract new customers\", ending with \"In conclusion, there are costs and benefits.\"</p>\n<ul>\n<li>Both sides are there, but the conclusion just summarises. The examiner''s report: \"many limited responses ended with a conclusion that was a summary rather than a supported judgement.\"</li>\n</ul>\n\n<p><strong>✅ Level 3 (5–6 marks):</strong> both sides, PLUS a judgement that answers the question with a reason:</p>\n<ul>\n<li>\"Overall, the choices are only economically sustainable if the improvements win enough new customers to cover the loan repayments and interest.\"</li>\n<li>The judgement says <em>under what conditions</em> — that''s what \"fully supported\" means.</li>\n</ul>\n\n<p><strong>One more trap:</strong> on \"evaluate the extent to which...\" questions, the mark scheme caps evaluation marks unless you directly address <em>the extent</em> — how big, how likely, what it depends on.</p>", "question": "A student writes brilliant analysis of the costs but never weighs anything up or gives a judgement. What does the real mark scheme cap them at?", "options": ["0 — analysis earns nothing", "4 out of 6", "6 out of 6 — analysis is what matters", "1–2 out of 6"]}'::jsonb, '{"answer": 3, "explain": "On an Evaluate question, evaluation IS the main skill — examiners reported strong-analysis-no-evaluation answers stuck at the bottom of the mark range. Every point needs a paired ''However...'' and the answer needs a supported judgement."}'::jsonb),
('economics:1-2-the-basic-economic-problem:tips:f03da883', 'economics', 'economics:1-2-the-basic-economic-problem', '1.2 The Basic Economic Problem', 'tips', 'mcq', 1, '{"readingTitle": "tip — Analyse vs Evaluate — and know your three sustainabilities", "reading": "<p><strong>Analyse</strong> (like \"Analyse the benefits of economic sustainability for CDS\"):</p>\n<ul>\n<li>Explain with chains of reasoning: \"this means... therefore... resulting in...\"</li>\n<li><strong>No judgement or conclusion needed.</strong> Don''t waste time writing one.</li>\n</ul>\n\n<p><strong>Evaluate</strong> (like \"Evaluate the costs... on their economic sustainability\"):</p>\n<ul>\n<li>Analyse + weigh both sides + a supported judgement.</li>\n<li>A judgement without a reason is capped at 5/6.</li>\n</ul>\n\n<p><strong>The three sustainabilities keep appearing in this topic''s exams — one question of each type has really been asked:</strong></p>\n<ul>\n<li><strong>Economic</strong> — best use of resources so growth can continue (Nina and Leo''s café; CDS)</li>\n<li><strong>Social</strong> — quality of life and fairness (the Asian Hornet''s effect on the UK; the Carwod road)</li>\n<li><strong>Environmental</strong> — resource use and pollution (free range farming at Calwith Farmers)</li>\n</ul>\n\n<p><strong>Before writing, underline which sustainability the question names</strong> — then check every sentence of your answer talks about that one.</p>", "question": "A 6-mark question starts with ''Analyse...''. Should your answer end with an overall judgement?", "options": ["No — Analyse needs chains of reasoning, not a judgement", "Only if you have spare time", "Yes — every 6-marker needs a conclusion", "Yes, but only one sentence"]}'::jsonb, '{"answer": 0, "explain": "Judgements belong to Evaluate questions. Analyse questions are marked on knowledge, application and chains of reasoning — a conclusion earns nothing extra (real OCR commentary confirms none is required)."}'::jsonb)
